select *
  from batch.trigger_misfire_pending
 where trigger_runtime_state_id = #{triggerRuntimeStateId}
   and scheduled_fire_time = #{scheduledFireTime}

select *
  from batch.trigger_misfire_pending
 where tenant_id = #{tenantId}
   and status = 'PENDING'
 order by detected_at desc
 limit #{limit}
